create extension if not exists pgcrypto;
create table if not exists public.profiles(id uuid primary key references auth.users(id) on delete cascade,full_name text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.clients(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,name text not null,company text,email text,phone text,status text not null default 'lead' check(status in('lead','active','inactive')),notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.projects(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,name text not null,client_name text,status text not null default 'planning' check(status in('planning','active','review','complete','archived')),priority text not null default 'medium' check(priority in('low','medium','high','urgent')),deadline date,budget numeric(12,2) not null default 0,description text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.studio_bookings(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,title text not null,client_name text,space text not null,booking_date date not null,start_time time,end_time time,status text not null default 'enquiry' check(status in('enquiry','confirmed','in_progress','completed','cancelled')),notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.transactions(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,description text not null,kind text not null check(kind in('income','expense')),amount numeric(12,2) not null check(amount>=0),status text not null default 'pending' check(status in('pending','paid','overdue','cancelled')),due_date date,category text,notes text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.conversations(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,title text not null default 'New conversation',created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.messages(id uuid primary key default gen_random_uuid(),conversation_id uuid not null references public.conversations(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,role text not null check(role in('user','assistant','system')),content text not null,created_at timestamptz not null default now());
create index if not exists clients_user_idx on public.clients(user_id);create index if not exists projects_user_idx on public.projects(user_id);create index if not exists bookings_user_date_idx on public.studio_bookings(user_id,booking_date);create index if not exists transactions_user_idx on public.transactions(user_id);create index if not exists messages_conversation_idx on public.messages(conversation_id,created_at);
alter table public.profiles enable row level security;alter table public.clients enable row level security;alter table public.projects enable row level security;alter table public.studio_bookings enable row level security;alter table public.transactions enable row level security;alter table public.conversations enable row level security;alter table public.messages enable row level security;
drop policy if exists "users_manage_own_profiles" on public.profiles;create policy "users_manage_own_profiles" on public.profiles for all using(auth.uid()=id) with check(auth.uid()=id);
do $$ declare t text;begin foreach t in array array['clients','projects','studio_bookings','transactions','conversations','messages'] loop execute format('drop policy if exists "users_manage_own_%1$s" on public.%1$I',t);execute format('create policy "users_manage_own_%1$s" on public.%1$I for all using (auth.uid() = user_id) with check (auth.uid() = user_id)',t);end loop;end $$;
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$begin insert into public.profiles(id,full_name) values(new.id,new.raw_user_meta_data->>'full_name');return new;end;$$;
drop trigger if exists on_auth_user_created on auth.users;create trigger on_auth_user_created after insert on auth.users for each row execute function public.handle_new_user();
